// Build transcript + exact stats + LLM prompt for the CURRENT group.
const MAX_CHARS = 40000; // guardrail for very high-volume days
const rows = $input.all().map(i => i.json)
  .filter(r => r && String(r.message ?? '').trim().length > 0);
const g = $('Loop Over Groups').first().json;

const total = rows.length;
const members = [...new Set(rows.map(r => r.sender_name).filter(Boolean))];

const pad = n => String(n).padStart(2, '0');
const months = ['Januari','Februari','Maret','April','Mei','Juni','Juli',
                'Agustus','September','Oktober','November','Desember'];
const jak = new Date(new Date().toLocaleString('en-US', { timeZone: 'Asia/Jakarta' }));
const dateStr = pad(jak.getDate()) + ' ' + months[jak.getMonth()] + ' ' + jak.getFullYear();

let transcript = rows.map(r => {
  const t = new Date(r.timestamp).toLocaleTimeString('id-ID',
    { hour: '2-digit', minute: '2-digit', timeZone: 'Asia/Jakarta' });
  return '[' + t + '] ' + (r.sender_name || 'Unknown') + ': ' + r.message;
}).join('\n');

let truncated = false;
if (transcript.length > MAX_CHARS) { transcript = transcript.slice(-MAX_CHARS); truncated = true; }

const prompt =
`Kamu adalah asisten yang merangkum percakapan grup WhatsApp dalam Bahasa Indonesia.
Berdasarkan transkrip, hasilkan dua daftar: "topics" (topik yang dibahas) dan
"action_items" (keputusan/tugas/hal yang harus ditindaklanjuti, sebutkan penanggung
jawab bila ada). Setiap item satu kalimat ringkas. Gabungkan pesan sejenis menjadi satu
topik. Jangan mengarang hal yang tidak ada di transkrip.
${truncated ? '(Catatan: sebagian pesan paling awal dipotong karena volume besar.)\n' : ''}
Transkrip:
${transcript}`;

return [{ json: {
  chat_jid: g.chat_jid, project_name: g.project_name, send_to: g.send_to,
  total, memberCount: members.length, memberList: members.join(', '), dateStr, prompt,
} }];

// Deterministically render the final message from the chain's structured output + DB stats.
// The Basic LLM Chain + Structured Output Parser returns the parsed object at $json.output.
let topics = [], actions = [];
try {
  const out = $json.output || {};
  topics = out.topics || [];
  actions = out.action_items || [];
} catch (e) {}

const bt = $('Build Transcript').first().json;
const ts = topics.length ? topics.map(t => '- ' + t).join('\n') : '- (tidak ada)';
const as = actions.length ? actions.map(a => '- ' + a).join('\n') : '- (tidak ada)';

const message =
  bt.project_name + ' Daily Summary\n' +
  '📅 ' + bt.dateStr + '\n\n' +
  'Topik Dibahas:\n' + ts + '\n\n' +
  'Pesan Penting / Action Items:\n' + as + '\n\n' +
  'Statistik:\n' +
  '- Total pesan: ' + bt.total + '\n' +
  '- Anggota aktif: ' + bt.memberCount + ' orang (' + bt.memberList + ')';

const status = (topics.length || actions.length) ? 'success' : 'error';
return [{ json: { chat_jid: bt.chat_jid, phone: bt.send_to, message, status,
                  total: bt.total, memberCount: bt.memberCount } }];

const bt = $('Build Transcript').first().json;
const message =
  bt.project_name + ' Daily Summary\n' +
  '📅 ' + bt.dateStr + '\n\n' +
  'Tidak ada aktivitas chat pada hari ini.';
return [{ json: { chat_jid: bt.chat_jid, phone: bt.send_to, message,
                  status: 'empty', total: 0, memberCount: 0 } }];
